// TestDaemon_RelatesToDoesNotBlock verifies that relates_to dependencies are informational
// and do not prevent an issue from being spawned (unlike blocks dependencies).
func TestDaemon_RelatesToDoesNotBlock(t *testing.T) {
	// Mock beads client that returns issues with relates_to dependencies
	mockClient := beads.NewMockClient()

	// Create two related issues - nlgg relates_to k793 (informational, not blocking)
	relatedIssue := beads.Issue{
		ID:           "orch-go-k793",
		Title:        "Related Audit",
		IssueType:    "task",
		Status:       "open",
		Priority:     2,
		Dependencies: nil,
	}
	mockClient.AddIssue(relatedIssue)

	// Issue with relates_to dependency (should be spawnable despite open dependency)
	issueWithRelatesTo := beads.Issue{
		ID:           "orch-go-nlgg",
		Title:        "Main Audit",
		IssueType:    "task",
		Status:       "open",
		Priority:     1,
		Labels:       []string{"triage:ready"},
		Dependencies: json.RawMessage(`[{"id":"orch-go-k793","title":"Related Audit","status":"open","dependency_type":"relates_to"}]`),
	}
	mockClient.AddIssue(issueWithRelatesTo)

	// Issue with blocks dependency (should NOT be spawnable)
	issueWithBlocks := beads.Issue{
		ID:           "orch-go-blocked",
		Title:        "Blocked Task",
		IssueType:    "task",
		Status:       "open",
		Priority:     0,
		Labels:       []string{"triage:ready"},
		Dependencies: json.RawMessage(`[{"id":"orch-go-k793","title":"Related Audit","status":"open","dependency_type":"blocks"}]`),
	}
	mockClient.AddIssue(issueWithBlocks)

	beads.SetDefaultClient(mockClient)
	defer beads.SetDefaultClient(nil)

	d := &Daemon{
		Config: Config{Label: "triage:ready"},
		listIssuesFunc: func() ([]Issue, error) {
			issues, err := mockClient.List()
			if err != nil {
				return nil, err
			}
			var result []Issue
			for _, i := range issues {
				result = append(result, Issue{
					ID:           i.ID,
					Title:        i.Title,
					IssueType:    i.IssueType,
					Status:       i.Status,
					Priority:     i.Priority,
					Labels:       i.Labels,
					Dependencies: i.Dependencies,
				})
			}
			return result, nil
		},
	}

	result, err := d.Preview()
	if err != nil {
		t.Fatalf("Preview() unexpected error: %v", err)
	}

	// Should be able to spawn nlgg (relates_to doesn't block)
	if result.Issue == nil {
		t.Fatal("Preview() expected spawnable issue (nlgg), got nil")
	}
	if result.Issue.ID != "orch-go-nlgg" {
		t.Errorf("Preview() spawnable issue ID = %q, want 'orch-go-nlgg'", result.Issue.ID)
	}

	// Verify rejection reasons
	rejectedByID := make(map[string]string)
	for _, r := range result.RejectedIssues {
		rejectedByID[r.Issue.ID] = r.Reason
	}

	// orch-go-blocked should be rejected (has blocks dependency)
	if reason, ok := rejectedByID["orch-go-blocked"]; !ok {
		t.Error("Preview() missing rejection for orch-go-blocked (has blocks dependency)")
	} else if !strings.Contains(reason, "blocked by dependencies") {
		t.Errorf("Preview() orch-go-blocked reason = %q, want to contain 'blocked by dependencies'", reason)
	}

	// orch-go-k793 should be rejected (no triage:ready label)
	if _, ok := rejectedByID["orch-go-k793"]; !ok {
		t.Error("Preview() missing rejection for orch-go-k793 (missing label)")
	}

	// orch-go-nlgg should NOT be in rejected list (relates_to doesn't block)
	if reason, ok := rejectedByID["orch-go-nlgg"]; ok {
		t.Errorf("Preview() unexpectedly rejected orch-go-nlgg with reason: %q", reason)
	}
}
